const input = $input.first().json;
const query = input.query || {};
const accion = query.accion || "inicio";

function escapar(texto) {
  if (!texto) return "";
  return String(texto)
    .replaceAll("'", "''")
    .replaceAll("\\", "\\\\");
}

function htmlBase(contenido) {
  return `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8">
  <title>Plataforma de Excedentes Alimentarios</title>
  <style>
    body{font-family:Arial,sans-serif;background:#f4f7f5;margin:0;padding:0}
    header{background:#2e7d32;color:white;padding:25px;text-align:center}
    main{width:90%;max-width:950px;margin:30px auto;background:white;padding:25px;border-radius:12px;box-shadow:0 2px 12px rgba(0,0,0,.12)}
    nav a{display:inline-block;margin:6px;padding:9px 13px;background:#e8f5e9;color:#2e7d32;text-decoration:none;border-radius:6px;font-weight:bold}
    nav a:hover{background:#c8e6c9} nav a.alerta{background:#ffebee;color:#c62828}
    input,select,textarea,button{width:100%;padding:10px;margin:8px 0 14px 0;border-radius:6px;border:1px solid #ccc;box-sizing:border-box}
    button{background:#2e7d32;color:white;border:none;cursor:pointer;font-weight:bold}
    button.btn-rojo{background:#c62828}
    .card{border:1px solid #ddd;border-left:6px solid #2e7d32;padding:15px;margin:15px 0;border-radius:8px;background:#fafafa}
    .critica{border-left-color:#d32f2f;background:#fff3f3}
    .vencida{border-left-color:#7b1fa2;background:#f3e5f5}
    .merma{border-left-color:#f57c00;background:#fff8e1}
    .badge{display:inline-block;background:#d32f2f;color:white;padding:4px 8px;border-radius:5px;font-size:12px;margin-right:6px}
    .badge-vencido{background:#7b1fa2} .frio{background:#0277bd} .badge-merma{background:#f57c00}
    .ok{background:#e8f5e9;border-left:6px solid #2e7d32;padding:12px;border-radius:8px}
    .error{background:#ffebee;border-left:6px solid #d32f2f;padding:12px;border-radius:8px}
    .advertencia{background:#fff3e0;border-left:6px solid #e65100;padding:12px;border-radius:8px;margin-bottom:16px}
    table{width:100%;border-collapse:collapse;margin-top:15px}
    th,td{border:1px solid #ddd;padding:10px;text-align:left} th{background:#e8f5e9}
  </style></head><body>
  <header><h1>Plataforma de Gestión de Excedentes Alimentarios</h1><p>n8n + Docker + PostgreSQL</p></header>
  <main>
    <nav>
      <a href="?accion=inicio">Inicio</a>
      <a href="?accion=registro">Registrar usuario</a>
      <a href="?accion=usuarios">Usuarios</a>
      <a href="?accion=publicar">Publicar excedente</a>
      <a href="?accion=publicar_vencido" class="alerta">⚠️ Reportar vencido</a>
      <a href="?accion=publicar_merma">🛍️ Merma estética</a>
      <a href="?accion=donaciones">Ver donaciones</a>
      <a href="?accion=notificaciones">Notificaciones ONG</a>
      <a href="?accion=reservas">Reservas</a>
      <a href="?accion=formulario_qr" class="alerta">🔍 Validar QR</a>
    </nav><hr>${contenido}
  </main></body></html>`;
}

// ── Acciones sin SQL ──────────────────────────────────────────────────────
if (accion === "inicio") {
  return [{ json: { accion, query, sqlType: "none", accionPendiente: null,
    html: htmlBase(`
      <h2>Bienvenido al sistema</h2>
      <ul>
        <li>Registro de usuarios Donante y Organización Social</li>
        <li>Publicación de excedentes alimentarios</li>
        <li>Validación de vencimiento y cadena de frío</li>
        <li>Alertas push para ONGs vía ntfy</li>
        <li>Reserva de donaciones con QR simulado</li>
        <li>Validación de entrega mediante código QR</li>
        <li>Publicación de merma estética</li>
        <li><strong>Persistencia en PostgreSQL</strong></li>
      </ul>
      <p class="ok"><strong>Estado:</strong> n8n + Docker + PostgreSQL funcionando.</p>
    `)
  }}];
}

if (accion === "registro") {
  return [{ json: { accion, query, sqlType: "none", accionPendiente: null,
    html: htmlBase(`
      <h2>Registrar usuario</h2>
      <form method="GET">
        <input type="hidden" name="accion" value="guardar_usuario">
        <label>Nombre:</label><input name="nombre" required>
        <label>Email:</label><input name="email" type="email" required>
        <label>Rol:</label>
        <select name="rol" required>
          <option value="DONANTE">Donante</option>
          <option value="ONG">Organización Social</option>
        </select>
        <label>Dirección:</label><input name="direccion" required>
        <button type="submit">Guardar usuario</button>
      </form>
    `)
  }}];
}

// ── Acciones con SELECT ───────────────────────────────────────────────────
if (accion === "publicar" || accion === "publicar_vencido") {
  return [{ json: { accion, query, sqlType: "select",
    sql: "SELECT * FROM usuarios WHERE rol = 'DONANTE' ORDER BY nombre;"
  }}];
}

if (accion === "usuarios") {
  return [{ json: { accion, query, sqlType: "select",
    sql: "SELECT * FROM usuarios ORDER BY creado_en DESC;"
  }}];
}

if (accion === "donaciones") {
  return [{ json: { accion, query, sqlType: "select",
    sql: `SELECT d.*, u.id as ong_id, u.nombre as ong_nombre
          FROM donaciones d LEFT JOIN usuarios u ON u.rol = 'ONG'
          WHERE d.estado = 'DISPONIBLE' ORDER BY d.vencimiento ASC;`
  }}];
}

if (accion === "notificaciones") {
  if (!query.usuarioId) {
    return [{ json: { accion, query, sqlType: "select",
      sql: "SELECT * FROM usuarios WHERE rol = 'ONG' ORDER BY nombre;"
    }}];
  }
  return [{ json: { accion, query, sqlType: "select",
    sql: `SELECT * FROM notificaciones WHERE usuario_id = ${Number(query.usuarioId)} ORDER BY fecha DESC;`
  }}];
}

if (accion === "reservas") {
  return [{ json: { accion, query, sqlType: "select",
    sql: "SELECT * FROM reservas ORDER BY fecha_reserva DESC;"
  }}];
}

// ── HU-05: Merma estética ─────────────────────────────────────────────────
if (accion === "publicar_merma") {
  return [{ json: { accion, query, sqlType: "select", accionPendiente: null,
    sql: "SELECT * FROM usuarios WHERE rol = 'DONANTE' ORDER BY nombre;"
  }}];
}

if (accion === "guardar_merma") {
  const vencimiento = new Date(query.vencimiento);
  const minimo = new Date(Date.now() + 2 * 60 * 60 * 1000);
  if (vencimiento < minimo) {
    return [{ json: { accion, query, sqlType: "none", accionPendiente: null,
      html: htmlBase(`<h2>Error</h2><p class="error">La fecha debe ser al menos 2 horas desde ahora.</p><a href="?accion=publicar_merma">Volver</a>`)
    }}];
  }
  return [{ json: { accion, query, sqlType: "insert", accionPendiente: null,
    sql: `INSERT INTO donaciones (donante_id, donante_nombre, nombre, categoria, cantidad, vencimiento, cadena_frio, observaciones, estado, tipo_excedente, tipo_merma)
          VALUES (${Number(query.donanteId)},
                 (SELECT nombre FROM usuarios WHERE id = ${Number(query.donanteId)}),
                 '${escapar(query.nombre)}', '${escapar(query.categoria)}',
                 ${Number(query.cantidad)}, '${query.vencimiento}',
                 ${query.cadenaFrio === "SI"}, '${escapar(query.estadoReal || "")}',
                 'DISPONIBLE', 'MERMA_ESTETICA', '${escapar(query.tipoMerma)}')
          RETURNING *;`
  }}];
}

// ── Acciones con INSERT ───────────────────────────────────────────────────
if (accion === "guardar_usuario") {
  return [{ json: { accion, query, sqlType: "insert", accionPendiente: null,
    sql: `INSERT INTO usuarios (nombre, email, rol, direccion)
          VALUES ('${escapar(query.nombre)}', '${escapar(query.email)}', 
                  '${query.rol === "ONG" ? "ONG" : "DONANTE"}', '${escapar(query.direccion)}')
          ON CONFLICT (email) DO UPDATE SET
            nombre = EXCLUDED.nombre,
            rol = EXCLUDED.rol,
            direccion = EXCLUDED.direccion
          RETURNING *;`
  }}];
}

if (accion === "guardar_donacion") {
  return [{ json: { accion, query, sqlType: "insert",
    accionPendiente: "guardar_donacion",
    payload: { nombre_producto: escapar(query.nombre), categoria: query.categoria, cantidad: query.cantidad, fecha_vencimiento: query.vencimiento },
    sql: `INSERT INTO donaciones (donante_id, donante_nombre, nombre, categoria, cantidad, vencimiento, cadena_frio, observaciones, estado)
          VALUES (${Number(query.donanteId)},
                 (SELECT nombre FROM usuarios WHERE id=${Number(query.donanteId)}),
                 '${escapar(query.nombre)}', '${escapar(query.categoria)}',
                 ${Number(query.cantidad)}, '${query.vencimiento}',
                 ${query.cadenaFrio === "SI"}, '${escapar(query.observaciones||"")}', 'DISPONIBLE')
          RETURNING *;`
  }}];
}

if (accion === "guardar_vencido") {
  if (new Date(query.vencimiento) >= new Date()) {
    return [{ json: { accion, query, sqlType: "none", accionPendiente: null,
      html: htmlBase(`<h2>Error</h2><p class="error">La fecha aún no ha vencido. Usa <a href="?accion=publicar">Publicar excedente</a>.</p>`)
    }}];
  }
  return [{ json: { accion, query, sqlType: "insert",
    accionPendiente: "guardar_vencido",
    payload: { nombre_producto: escapar(query.nombre), categoria: query.categoria, cantidad: query.cantidad, fecha_vencimiento: query.vencimiento },
    sql: `INSERT INTO donaciones (donante_id, donante_nombre, nombre, categoria, cantidad, vencimiento, cadena_frio, observaciones, estado)
          VALUES (${Number(query.donanteId)},
                 (SELECT nombre FROM usuarios WHERE id=${Number(query.donanteId)}),
                 '${escapar(query.nombre)}', '${escapar(query.categoria)}',
                 ${Number(query.cantidad)}, '${query.vencimiento}',
                 false, '${escapar(query.observaciones||"")}', 'VENCIDO')
          RETURNING *;`
  }}];
}

if (accion === "reservar") {
  return [{ json: { accion, query, sqlType: "insert", accionPendiente: null,
    sql: `WITH upd AS (
            UPDATE donaciones SET estado = 'RESERVADA'
            WHERE id = ${Number(query.donacionId)} AND estado = 'DISPONIBLE'
            RETURNING *
          ),
          ins AS (
            INSERT INTO reservas (donacion_id, producto, usuario_id, organizacion_nombre, codigo_qr)
            SELECT upd.id, upd.nombre,
                   ${Number(query.usuarioId)},
                   (SELECT nombre FROM usuarios WHERE id = ${Number(query.usuarioId)}),
                   'QR-' || upd.id || '-' || ${Number(query.usuarioId)}
            FROM upd RETURNING *
          )
          SELECT ins.*, u.direccion AS direccion_donante
          FROM ins
          JOIN donaciones d ON d.id = ins.donacion_id
          JOIN usuarios u ON u.id = d.donante_id;`
  }}];
}

// ── HU-11: Formulario de validación QR ───────────────────────────────────────
if (accion === "formulario_qr") {
  return [{ json: { accion, query, sqlType: "none", accionPendiente: null,
    html: htmlBase(`
      <h2>🔍 Validar entrega por código QR</h2>
      <div class="advertencia">
        <strong>Instrucción:</strong> Ingresa el código QR generado durante la reserva para confirmar que el donante entregó el producto.
      </div>
      <form method="GET">
        <input type="hidden" name="accion" value="validar_qr">
        <label>Código QR de retiro:</label>
        <input name="codigo_qr" placeholder="Ej: QR-1748304729-5" required>
        <button type="submit">✅ Validar entrega</button>
      </form>
    `)
  }}];
}

// ── HU-11: Ejecutar validación QR con transacción PostgreSQL ─────────────────
if (accion === "validar_qr") {
  const codigoQr = escapar(query.codigo_qr || "");
  if (!codigoQr) {
    return [{ json: { accion, query, sqlType: "none", accionPendiente: null,
      html: htmlBase(`<h2>Error</h2><p class="error">Debes ingresar un código QR.</p><a href="?accion=formulario_qr">Volver</a>`)
    }}];
  }
  return [{ json: { accion, query, sqlType: "insert", accionPendiente: null,
    sql: `
      WITH verificacion AS (
        SELECT r.id AS reserva_id, r.donacion_id, r.usuario_id,
               r.organizacion_nombre, r.estado AS reserva_estado,
               r.codigo_qr, r.fecha_reserva,
               d.nombre AS producto, d.cantidad,
               d.donante_id, d.donante_nombre
        FROM reservas r
        JOIN donaciones d ON d.id = r.donacion_id
        WHERE r.codigo_qr = '${codigoQr}'
      ),
      actualizar_reserva AS (
        UPDATE reservas
        SET estado = 'COMPLETADA', fecha_entrega = NOW()
        WHERE codigo_qr = '${codigoQr}' AND estado = 'ACTIVA'
        RETURNING id, fecha_entrega
      ),
      actualizar_donacion AS (
        UPDATE donaciones
        SET estado = 'ENTREGADA'
        WHERE id = (SELECT donacion_id FROM verificacion)
          AND EXISTS (SELECT 1 FROM actualizar_reserva)
        RETURNING id
      ),
      insertar_notif AS (
        INSERT INTO notificaciones (usuario_id, donacion_id, mensaje, es_alerta_vencido)
        SELECT v.donante_id, v.donacion_id,
          '✅ Entrega confirmada: ' || v.organizacion_nombre ||
          ' retiró ' || v.cantidad || ' unidades de ' || v.producto ||
          '. Código QR: ' || v.codigo_qr,
          false
        FROM verificacion v
        WHERE EXISTS (SELECT 1 FROM actualizar_reserva)
        RETURNING id
      )
      SELECT v.*,
        ar.fecha_entrega,
        (SELECT COUNT(*) FROM actualizar_reserva)  AS reserva_actualizada,
        (SELECT COUNT(*) FROM actualizar_donacion)  AS donacion_actualizada,
        (SELECT COUNT(*) FROM insertar_notif)        AS notif_insertada
      FROM verificacion v
      LEFT JOIN actualizar_reserva ar ON true;
    `
  }}];
}

return [{ json: { accion, query, sqlType: "none", accionPendiente: null,
  html: htmlBase(`<h2>Acción no reconocida</h2><p>La acción <strong>${accion}</strong> no existe.</p>`)
}}];

const meta = $('Code in JavaScript').first().json;
const accion = meta.accion || "inicio";
const query = meta.query || {};

// Si ya viene HTML listo (inicio, registro, error fecha), devolver directo
if (meta.html) {
  return [{ json: { html: meta.html, accionPendiente: null }}];
}

// Obtener rows correctamente según la ruta
let rows = [];

if (accion === "reservar") {
  rows = $('Execute a SQL query').all().map(i => i.json);
} else if (accion === "validar_qr") {
  rows = $('Execute a SQL query').all().map(i => i.json);
} else {
  try {
    const notifData = $('Insertar Notificaciones').first().json;
    if (notifData && notifData.rows && notifData.rows.length > 0) {
      rows = notifData.rows;
    } else {
      rows = $input.all().map(i => i.json);
    }
  } catch(e) {
    rows = $input.all().map(i => i.json);
  }
}

function formatFecha(fecha) {
  if (!fecha) return '';
  return new Date(fecha).toLocaleString('es-CL', {
    timeZone: 'America/Santiago',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  });
}

function htmlBase(contenido) {
  return `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8">
  <title>Excedentes Alimentarios</title>
  <style>
    body{font-family:Arial,sans-serif;background:#f4f7f5;margin:0;padding:0}
    header{background:#2e7d32;color:white;padding:25px;text-align:center}
    main{width:90%;max-width:950px;margin:30px auto;background:white;padding:25px;border-radius:12px;box-shadow:0 2px 12px rgba(0,0,0,.12)}
    nav a{display:inline-block;margin:6px;padding:9px 13px;background:#e8f5e9;color:#2e7d32;text-decoration:none;border-radius:6px;font-weight:bold}
    nav a:hover{background:#c8e6c9} nav a.alerta{background:#ffebee;color:#c62828}
    input,select,textarea,button{width:100%;padding:10px;margin:8px 0 14px 0;border-radius:6px;border:1px solid #ccc;box-sizing:border-box}
    button{background:#2e7d32;color:white;border:none;cursor:pointer;font-weight:bold}
    button.btn-rojo{background:#c62828}
    .card{border:1px solid #ddd;border-left:6px solid #2e7d32;padding:15px;margin:15px 0;border-radius:8px;background:#fafafa}
    .critica{border-left-color:#d32f2f;background:#fff3f3}
    .vencida{border-left-color:#7b1fa2;background:#f3e5f5}
    .badge{display:inline-block;background:#d32f2f;color:white;padding:4px 8px;border-radius:5px;font-size:12px;margin-right:6px}
    .badge-vencido{background:#7b1fa2} .frio{background:#0277bd}
    .ok{background:#e8f5e9;border-left:6px solid #2e7d32;padding:12px;border-radius:8px}
    .error{background:#ffebee;border-left:6px solid #d32f2f;padding:12px;border-radius:8px}
    .advertencia{background:#fff3e0;border-left:6px solid #e65100;padding:12px;border-radius:8px;margin-bottom:16px}
    table{width:100%;border-collapse:collapse;margin-top:15px}
    th,td{border:1px solid #ddd;padding:10px;text-align:left} th{background:#e8f5e9}
  </style></head><body>
  <header><h1>Plataforma de Gestión de Excedentes Alimentarios</h1><p>n8n + Docker + PostgreSQL</p></header>
  <main>
    <nav>
      <a href="?accion=inicio">Inicio</a>
      <a href="?accion=registro">Registrar usuario</a>
      <a href="?accion=usuarios">Usuarios</a>
      <a href="?accion=publicar">Publicar excedente</a>
      <a href="?accion=publicar_vencido" class="alerta">⚠️ Reportar vencido</a>
      <a href="?accion=donaciones">Ver donaciones</a>
      <a href="?accion=notificaciones">Notificaciones ONG</a>
      <a href="?accion=reservas">Reservas</a>
      <a href="?accion=formulario_qr" class="alerta">🔍 Validar QR</a>
    </nav><hr>${contenido}
  </main></body></html>`;
}

if (accion === "guardar_usuario") {
  const u = rows[0] || {};
  return [{ json: { accionPendiente: null,
    html: htmlBase(`
      <h2>✅ Usuario registrado</h2>
      <div class="ok">
        <p><strong>ID:</strong> ${u.id}</p>
        <p><strong>Nombre:</strong> ${u.nombre}</p>
        <p><strong>Email:</strong> ${u.email}</p>
        <p><strong>Rol:</strong> ${u.rol}</p>
        <p><strong>Dirección:</strong> ${u.direccion}</p>
        <p><strong>Registrado:</strong> ${formatFecha(u.creado_en)}</p>
      </div>
      <a href="?accion=usuarios">Ver todos los usuarios</a>
    `)
  }}];
}

if (accion === "usuarios") {
  const filas = rows.map(u => `
    <tr><td>${u.id}</td><td>${u.nombre}</td><td>${u.email}</td><td>${u.rol}</td><td>${u.direccion||''}</td><td>${formatFecha(u.creado_en)}</td></tr>
  `).join("");
  return [{ json: { accionPendiente: null,
    html: htmlBase(`
      <h2>Usuarios registrados</h2>
      <table>
        <tr><th>ID</th><th>Nombre</th><th>Email</th><th>Rol</th><th>Dirección</th><th>Registrado</th></tr>
        ${filas || '<tr><td colspan="6">No hay usuarios registrados.</td></tr>'}
      </table>
    `)
  }}];
}

// ── HU-05: Renderizar merma estética ─────────────────────────────────────────
if (accion === "publicar_merma") {
  if (rows.length === 0) {
    return [{ json: { accionPendiente: null,
      html: htmlBase(`<h2>🛍️ Merma estética</h2><p class="error">Primero registra un Donante.</p><a href="?accion=registro">Registrar usuario</a>`)
    }}];
  }
  const opts = rows.map(u => `<option value="${u.id}">${u.nombre}</option>`).join("");
  return [{ json: { accionPendiente: null,
    html: htmlBase(`
      <h2>🛍️ Publicar producto con empaque dañado</h2>
      <div class="advertencia"><strong>Atención:</strong> Solo para productos en buen estado con daño estético.</div>
      <form method="GET">
        <input type="hidden" name="accion" value="guardar_merma">
        <label>Donante:</label><select name="donanteId" required>${opts}</select>
        <label>Nombre del producto:</label><input name="nombre" placeholder="Ej: Caja de galletas" required>
        <label>Categoría:</label>
        <select name="categoria" required>
          <option value="Panadería">Panadería</option>
          <option value="Lácteos">Lácteos</option>
          <option value="Frutas y verduras">Frutas y verduras</option>
          <option value="Abarrotes">Abarrotes</option>
          <option value="Otros">Otros</option>
        </select>
        <label>Cantidad:</label><input name="cantidad" type="number" required>
        <label>Fecha y hora de vencimiento:</label><input name="vencimiento" type="datetime-local" required>
        <label>Tipo de daño estético:</label>
        <select name="tipoMerma" required>
          <option value="EMPAQUE_GOLPEADO">Empaque golpeado</option>
          <option value="ETIQUETA_DESPRENDIDA">Etiqueta desprendida</option>
          <option value="FORMA_IRREGULAR">Forma irregular</option>
          <option value="COLOR_ATIPICO">Color atípico</option>
          <option value="OTROS_ESTETICO">Otro daño estético</option>
        </select>
        <label>Descripción del estado real del producto:</label>
        <textarea name="estadoReal" placeholder="Ej: Producto apto para consumo, solo la caja tiene un golpe." required></textarea>
        <label>Cadena de frío:</label>
        <select name="cadenaFrio">
          <option value="NO">No requiere</option>
          <option value="SI">Sí requiere</option>
        </select>
        <button type="submit">Publicar producto con merma estética</button>
      </form>
    `)
  }}];
}

if (accion === "guardar_merma") {
  const d = rows[0] || {};
  return [{ json: { accionPendiente: null,
    html: htmlBase(`
      <h2>✅ Producto con merma estética publicado</h2>
      <div class="ok">
        <p><strong>Producto:</strong> ${d.nombre}</p>
        <p><strong>Donante:</strong> ${d.donante_nombre}</p>
        <p><strong>Categoría:</strong> ${d.categoria}</p>
        <p><strong>Cantidad:</strong> ${d.cantidad}</p>
        <p><strong>Vencimiento:</strong> ${formatFecha(d.vencimiento)}</p>
        <p><strong>Tipo de daño:</strong> ${(d.tipo_merma || "").replace(/_/g, " ")}</p>
