    payload: meta.payload,
    html: htmlBase(`
      <h2>⚠️ Producto vencido registrado</h2>
      <div class="critica">
        <p><strong>Producto:</strong> ${d.nombre}</p>
        <p><strong>Donante:</strong> ${d.donante_nombre}</p>
