      <a href="?accion=notificaciones">Ver notificaciones</a>
    `)
  }}];
}

if (accion === "donaciones") {
  const seen = new Set();
  const donaciones = rows.filter(r => { if(seen.has(r.id)) return false; seen.add(r.id); return true; });
  const ongMap = new Map();
  rows.forEach(r => { if(r.ong_id) ongMap.set(String(r.ong_id), r.ong_nombre); });
  const opcionesONG = [...ongMap.entries()].map(([id,nom]) => `<option value="${id}">${nom}</option>`).join("");

  const lista = donaciones.map(d => {
    const horas = (new Date(d.vencimiento).getTime() - new Date().getTime()) / 3600000;
    const critica = horas <= 6 && horas >= 0;
    return `
      <div class="card ${critica ? 'critica' : ''}">
        <h3>${d.nombre}</h3>
        ${critica ? '<span class="badge">Urgente</span>' : ''}
        ${d.cadena_frio ? '<span class="badge frio">Cadena de frío</span>' : ''}
        <p><strong>Donante:</strong> ${d.donante_nombre}</p>
        <p><strong>Categoría:</strong> ${d.categoria}</p>
        <p><strong>Cantidad:</strong> ${d.cantidad}</p>
        <p><strong>Vencimiento:</strong> ${formatFecha(d.vencimiento)}</p>
        <p><strong>Observaciones:</strong> ${d.observaciones || 'Sin observaciones'}</p>
        ${opcionesONG
          ? `<form method="GET">
              <input type="hidden" name="accion" value="reservar">
              <input type="hidden" name="donacionId" value="${d.id}">
              <label>Organización que reserva:</label>
              <select name="usuarioId" required>${opcionesONG}</select>
              <button type="submit">Reservar donación</button>
            </form>`
          : '<p class="error">No hay ONGs registradas para reservar.</p>'
        }
      </div>`;
  }).join("");

  return [{ json: { accionPendiente: null,
    html: htmlBase(`<h2>Donaciones disponibles</h2>${lista || '<p>No hay donaciones disponibles.</p>'}`)
  }}];
}

if (accion === "notificaciones") {
  if (!query.usuarioId) {
    const opts = rows.map(u => `<option value="${u.id}">${u.nombre}</option>`).join("");
    return [{ json: { accionPendiente: null,
      html: htmlBase(`
        <h2>Notificaciones ONG</h2>
        <form method="GET">
          <input type="hidden" name="accion" value="notificaciones">
