  return [{ json: { accionPendiente: null,
    html: htmlBase(`<h2>Notificaciones</h2>${lista || '<p>No hay notificaciones.</p>'}`)
  }}];
}

if (accion === "reservas") {
  const lista = rows.map(r => `
    <div class="card">
      <h3>${r.producto}</h3>
      <p><strong>Organización:</strong> ${r.organizacion_nombre}</p>
      <p><strong>Fecha reserva:</strong> ${formatFecha(r.fecha_reserva)}</p>
      <p><strong>Estado:</strong> ${r.estado}</p>
      <p><strong>QR:</strong> ${r.codigo_qr}</p>
