// ── HU-11: Renderizar resultado de validación QR ─────────────────────────────
if (accion === "validar_qr") {
  if (rows.length === 0 || !rows[0].reserva_id) {
    return [{ json: { accionPendiente: null,
      html: htmlBase(`
        <h2>❌ Código QR no válido</h2>
        <div class="error">
          <p>El código ingresado <strong>no existe</strong> en el sistema. Verifica que sea correcto.</p>
        </div>
        <a href="?accion=formulario_qr">← Intentar de nuevo</a>
      `)
    }}];
  }

  const r = rows[0];

  if (r.reserva_estado === 'COMPLETADA') {
    return [{ json: { accionPendiente: null,
      html: htmlBase(`
        <h2>⚠️ Código ya utilizado</h2>
        <div class="advertencia">
          <p>Este código QR <strong>ya fue canjeado</strong> en una entrega anterior.</p>
          <p><strong>Producto:</strong> ${r.producto}</p>
          <p><strong>Organización:</strong> ${r.organizacion_nombre}</p>
          <p><strong>Reserva:</strong> ${r.codigo_qr}</p>
        </div>
        <a href="?accion=formulario_qr">← Validar otro código</a>
      `)
    }}];
  }

  if (Number(r.reserva_actualizada) > 0) {
    return [{ json: { accionPendiente: null,
      html: htmlBase(`
        <h2>✅ Entrega validada correctamente</h2>
        <div class="ok">
          <p><strong>Producto:</strong> ${r.producto}</p>
          <p><strong>Cantidad:</strong> ${r.cantidad}</p>
          <p><strong>Organización receptora:</strong> ${r.organizacion_nombre}</p>
          <p><strong>Donante:</strong> ${r.donante_nombre}</p>
          <p><strong>Código QR:</strong> ${r.codigo_qr}</p>
          <p><strong>Fecha y hora de entrega:</strong> ${formatFecha(r.fecha_entrega)}</p>
          <p><strong>Estado donación:</strong> <span class="badge" style="background:#388e3c;color:white;padding:4px 8px;border-radius:5px;">ENTREGADA</span></p>
        </div>
        <p class="ok">✅ Notificación enviada al donante automáticamente.</p>
        <br>
        <a href="?accion=reservas">Ver todas las reservas</a>
      `)
    }}];
  }

  return [{ json: { accionPendiente: null,
    html: htmlBase(`
      <h2>❌ Error al validar</h2>
      <div class="error">
        <p>Ocurrió un error inesperado al procesar el código. Intenta nuevamente.</p>
      </div>
      <a href="?accion=formulario_qr">← Volver</a>
    `)
  }}];
}

return [{ json: { accionPendiente: null,
  html: htmlBase(`<h2>Acción no reconocida</h2><p>Acción: <strong>${accion}</strong></p>`)
}}];

const meta = $('Code in JavaScript').first().json;
const accion = meta.accion;
const rows = $input.all().map(i => i.json);

// Acciones que no necesitan notificaciones, pasar directo
if (accion !== 'guardar_donacion' && accion !== 'guardar_vencido') {
  return [{ json: { ...meta, rows, sqlNotif: null }}];
}

if (accion === 'guardar_donacion' || accion === 'guardar_vencido') {
  const donacion = rows[0];
  if (donacion && donacion.id) {
    const esVencido = accion === 'guardar_vencido';
    const mensaje = esVencido
      ? `⚠️ ALERTA VENCIDO: ${donacion.nombre} (${donacion.cantidad} uds) vencido el ${donacion.vencimiento}`
      : `Nueva donación: ${donacion.nombre} (${donacion.cantidad} uds) disponible`;
    return [{ json: {
      ...meta,
      rows,
      sqlNotif: `INSERT INTO notificaciones (usuario_id, organizacion_nombre, donacion_id, mensaje, es_alerta_vencido)
                 SELECT u.id, u.nombre, ${donacion.id}, '${mensaje.replaceAll("'","''")}', ${esVencido}
                 FROM usuarios u WHERE u.rol = 'ONG';`
    }}];
  }
}

return [{ json: { ...meta, rows, sqlNotif: null }}];
